        "Dragon, Red": { category: "Dragon", size: "H", ac: -1, hd: "10-12", thac0: 9, damage: "1d8/1d8/3d10", xp: 5000, source: "Monstrous Manual", saves: "5/7/6/8/8", immunities: "Fire", special: "Fire breath (90 ft cone, 2d10/HD), Detect gems (1 mile), Heat metal (3/day), Infravision, Immune to fire", appearance: "The most feared dragons with deep red scales, massive wings, and a terrible temper. They are greedy, cruel, and the largest of the chromatic dragons.", frequency: "Very Rare", encounter: "2%" },
